class RijndaelCore {
    protected $_key;
    protected $_iv;

    public function __construct($key, $iv) {
        $this->_key = $key;
        $this->_iv  = base64_decode($iv);
    }

    // Returns "<hmac>:base64(AES-128-CBC ciphertext)"
    public function encrypt($plaintext) {
        if (strlen($plaintext) >= 1048576) { return false; }
        $cipherText = openssl_encrypt($plaintext, 'AES-128-CBC', $this->_key, OPENSSL_RAW_DATA, $this->_iv);
        return $this->generateHmac($cipherText) . ':' . base64_encode($cipherText);
    }

    // Validates HMAC BEFORE decrypting; returns false on any mismatch
    public function decrypt($cipherText) {
        $data = explode(':', $cipherText);
        if (count($data) != 2) { return false; }
        list($hmac, $encrypted) = $data;
        $encrypted = base64_decode($encrypted);
        $newHmac   = $this->generateHmac($encrypted);
        if ($hmac !== $newHmac) { return false; }  // MAC check -- REJECT if tampered
        return openssl_decrypt($encrypted, 'AES-128-CBC', $this->_key, OPENSSL_RAW_DATA, $this->_iv);
    }

    // HMAC-SHA256 over (iv || "rijndael-128" || ciphertext) using a KDF-derived key
    protected function generateHmac($encrypted) {
        $macKey = $this->generateKeygenS2k('sha256', $this->_key, $this->_iv, 32);
        return hash_hmac('sha256', $this->_iv . 'rijndael-128' . $encrypted, $macKey);
    }

    protected function generateKeygenS2k($hash, $password, $salt, $bytes) {
        $result = '';
        foreach (range(0, ceil($bytes / strlen(hash($hash, '', true))) - 1) as $i) {
            $result .= hash($hash,
                str_repeat("\0", $i) . str_pad(substr($salt, 0, 8), 8, "\0", STR_PAD_RIGHT) . $password,
                true);
        }
        return substr($result, 0, $bytes);
    }
}
